interface AppConfig {
  server: { host: string; port: number };
  database: { url: string; pool_size: number; timeout_ms: number };
  auth: { secret: string; token_ttl: number };
  logging: { level: string; format: string };
}

function getEnvVar(key: string): string {
  const value = process.env[key];
  if (!value) {
    throw new Error(`Environment variable ${key} is required but not set`);
  }
  return value;
}

function getEnvVarAsNumber(key: string): number {
  const value = getEnvVar(key);
  const num = parseInt(value, 10);
  if (isNaN(num)) {
    throw new Error(`Environment variable ${key} must be a valid number, got: ${value}`);
  }
  return num;
}

export function loadConfig(): AppConfig {
  return {
    server: {
      host: getEnvVar('SERVER_HOST'),
      port: getEnvVarAsNumber('SERVER_PORT'),
    },
    database: {
      url: getEnvVar('DATABASE_URL'),
      pool_size: 10, // Static value preserved from YAML
      timeout_ms: 5000, // Static value preserved from YAML
    },
    auth: {
      secret: getEnvVar('AUTH_SECRET'),
      token_ttl: 3600, // Static value preserved from YAML
    },
    logging: {
      level: getEnvVar('LOG_LEVEL'),
      format: 'json', // Static value preserved from YAML
    },
  };
}

export type { AppConfig };

// Quick test to verify the new config works
process.env.SERVER_HOST = 'localhost';
process.env.SERVER_PORT = '3000';
