process.env.AUTH_SECRET = 'my-secret-key';
process.env.LOG_LEVEL = 'info';

const { loadConfig } = require('./src/config-loader.ts');

try {
  const config = loadConfig();
  console.log('✅ Configuration loaded successfully:');
  console.log(JSON.stringify(config, null, 2));

  // Verify static values are preserved
  console.log('\n✅ Static values preserved:');
  console.log(`pool_size: ${config.database.pool_size} (should be 10)`);
  console.log(`timeout_ms: ${config.database.timeout_ms} (should be 5000)`);
  console.log(`token_ttl: ${config.auth.token_ttl} (should be 3600)`);
  console.log(`format: ${config.logging.format} (should be "json")`);
} catch (error) {
  console.error('❌ Configuration failed:', error.message);
}

interface AppConfig {
  server: { host: string; port: number };
  database: { url: string; pool_size: number; timeout_ms: number };
  auth: { secret: string; token_ttl: number };
  logging: { level: string; format: string };
}

export function loadConfig(): AppConfig {
  // Read environment variables with validation
  const serverHost = process.env.SERVER_HOST;
  const serverPort = process.env.SERVER_PORT;
  const databaseUrl = process.env.DATABASE_URL;
  const authSecret = process.env.AUTH_SECRET;
  const logLevel = process.env.LOG_LEVEL;

  // Validate required environment variables
  if (!serverHost) {
    throw new Error('SERVER_HOST environment variable is required');
  }
  if (!serverPort) {
    throw new Error('SERVER_PORT environment variable is required');
  }
  if (!databaseUrl) {
    throw new Error('DATABASE_URL environment variable is required');
  }
  if (!authSecret) {
    throw new Error('AUTH_SECRET environment variable is required');
  }
  if (!logLevel) {
    throw new Error('LOG_LEVEL environment variable is required');
  }

  // Parse and validate PORT as number
  const port = parseInt(serverPort, 10);
  if (isNaN(port) || port <= 0) {
    throw new Error('SERVER_PORT must be a valid positive number');
  }

  return {
    server: {
      host: serverHost,
      port: port
    },
    database: {
      url: databaseUrl,
      pool_size: 10,      // Static value preserved
      timeout_ms: 5000    // Static value preserved
    },
    auth: {
      secret: authSecret,
      token_ttl: 3600     // Static value preserved
    },
    logging: {
      level: logLevel,
      format: 'json'      // Static value preserved
    }
  };
}

