155	/**
156	 * Routes events between buses based on configurable rules.
157	 * Depends on EventBus for both source and target subscriptions.
158	 */
159	export class EventRouter {
160	  private rules: Array<{ pattern: RegExp; target: EventBus; transform?: (p: EventPayload) => EventPayload }> = [];
161	
162	  constructor(private source: EventBus) {}
163	
164	  /** Add a routing rule: events matching the pattern get forwarded to target */
165	  addRule(pattern: string | RegExp, target: EventBus, transform?: (p: EventPayload) => EventPayload): void {
166	    const regex = typeof pattern === 'string' ? new RegExp(pattern) : pattern;
167	    this.rules.push({ pattern: regex, target, transform });
168	  }
169	
170	  /** Start routing — subscribe to all current event names on source */
171	  start(): void {
172	    const names = this.source.getEventNames();
173	    for (const name of names) {
174	      this.source.on(name, (payload) => {
175	        for (const rule of this.rules) {
176	          if (rule.pattern.test(name)) {
177	            const transformed = rule.transform ? rule.transform(payload) : payload;
178	            rule.target.emit(name, transformed);
179	          }
180	        }
181	      });
182	    }
183	  }
184	
185	  /** Get the number of active routing rules */
186	  getRuleCount(): number {
187	    return this.rules.length;
188	  }
189	}
